-- Create a stored procedure (PostgreSQL)
CREATE OR REPLACE PROCEDURE transfer_funds(
    p_from_account INT,
    p_to_account INT,
    p_amount DECIMAL
)
LANGUAGE plpgsql
AS $$
DECLARE
    v_balance DECIMAL;
BEGIN
    -- Check sufficient balance
    SELECT balance INTO v_balance
    FROM accounts WHERE id = p_from_account FOR UPDATE;

    IF v_balance < p_amount THEN
        RAISE EXCEPTION 'Insufficient funds: % available', v_balance;
    END IF;

    -- Perform transfer atomically
    UPDATE accounts SET balance = balance - p_amount WHERE id = p_from_account;
    UPDATE accounts SET balance = balance + p_amount WHERE id = p_to_account;

    -- Log the transaction
    INSERT INTO transaction_log(from_id, to_id, amount, ts)
    VALUES (p_from_account, p_to_account, p_amount, NOW());

    COMMIT;
END;
$$;

-- Call it
CALL transfer_funds(101, 202, 500.00);

-- Hash sharding (application-level routing)
import hashlib

def get_shard(user_id: int, num_shards: int = 4) -> int:
    return user_id % num_shards
    # user_id=42 -> shard 2
    # user_id=43 -> shard 3

# Each shard is a separate database connection
shards = [
    connect('shard-0.db.internal'),
    connect('shard-1.db.internal'),
    connect('shard-2.db.internal'),
    connect('shard-3.db.internal'),
]

def get_user(user_id: int):
    shard = shards[get_shard(user_id)]
    return shard.execute('SELECT * FROM users WHERE id = ?', user_id)

# Problem: to JOIN orders with users, you need to know which shard
# each user lives on — cross-shard JOINs require app-level joins

-- PostgreSQL declarative partitioning (single DB, multi-file)
CREATE TABLE orders (
    id BIGINT, user_id INT, created_at DATE, total DECIMAL
) PARTITION BY RANGE (created_at);

CREATE TABLE orders_2024 PARTITION OF orders
    FOR VALUES FROM ('2024-01-01') TO ('2025-01-01');

CREATE TABLE orders_2025 PARTITION OF orders
    FOR VALUES FROM ('2025-01-01') TO ('2026-01-01');

-- Table: sales(month, product, revenue)
-- Goal: one column per product, rows per month

-- Standard approach: conditional aggregation (works everywhere)
SELECT
    month,
    SUM(CASE WHEN product = 'Phone'  THEN revenue ELSE 0 END) AS Phone,
    SUM(CASE WHEN product = 'Laptop' THEN revenue ELSE 0 END) AS Laptop,
    SUM(CASE WHEN product = 'Tablet' THEN revenue ELSE 0 END) AS Tablet
FROM sales
GROUP BY month
ORDER BY month;

-- SQL Server native PIVOT
SELECT month, [Phone], [Laptop], [Tablet]
FROM sales
PIVOT (
    SUM(revenue)
    FOR product IN ([Phone], [Laptop], [Tablet])
) AS pivoted;

-- Dynamic pivot in MySQL (when products are unknown at query time)
SET @sql = NULL;
SELECT GROUP_CONCAT(
    DISTINCT CONCAT('SUM(CASE WHEN product = ''', product, ''' THEN revenue ELSE 0 END) AS ', product)
) INTO @sql FROM sales;

SET @sql = CONCAT('SELECT month, ', @sql, ' FROM sales GROUP BY month');
PREPARE stmt FROM @sql;
EXECUTE stmt;
